  "partialurl": "Content-Snipped-Test-deleted",
  "isroot": false,
  "rootwebpageid": "03bf912f-8605-ec75-142e-9577f6514589",
  "title": "Content Snipped Test",
  "summary": "<p>This is a sample landing page designed to be a starting point for your website</p>",
  "copy": "
{% comment %}
  Power Pages Login Template
  - Shows local sign-in (username/password) and external identity providers
  - Redirects signed-in users away from login page
{% endcomment %}

{% if user %}
  <!-- If the user is already signed in, send them to homepage or a dashboard -->
  <script>
    window.location.href = "{{ website.adx_homepage.url | default: '/' }}";
  </script>
{% endif %}

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <title>Sign in</title>
  <meta name="viewport" content="width=device-width, initial-scale=1">

  <!-- Optional: Use Power Pages’ Bootstrap if present; otherwise the CSS below handles layout -->
  <style>
    :root{
      --bg: #0f172a;
      --card: #111827;
      --text: #e5e7eb;
      --muted: #9ca3af;
      --primary: #2563eb;
      --primary-700:#1d4ed8;
      --border:#1f2937;
      --success:#16a34a;
      --error:#ef4444;
    }

    *{box-sizing:border-box}
    body{
      margin:0;
      min-height:100vh;
      display:flex;
      align-items:center;
      justify-content:center;
      background: radial-gradient(1000px 600px at 20% 10%, #0b1226 20%, var(--bg)),
                  radial-gradient(800px 480px at 80% 80%, #0b1226 10%, #0f172a);
      font-family: system-ui, -apple-system, Segoe UI, Roboto, "Helvetica Neue", Arial, "Noto Sans", "Liberation Sans", sans-serif;
      color:var(--text);
    }
    .container{
      width:100%;
      max-width:960px;
      padding:24px;
    }
    .card{
      display:grid;
      grid-template-columns: 1fr 1fr;
      gap:0;
      background:rgba(17,24,39,0.75);
      border:1px solid var(--border);
      border-radius:16px;
      overflow:hidden;
      box-shadow: 0 20px 40px rgba(0,0,0,0.45);
      backdrop-filter: blur(6px);
    }
    @media (max-width: 900px){
      .card{ grid-template-columns: 1fr; }
      .visual{ display:none; }
    }

    .content{
      padding:32px 32px 28px;
    }
    .brand{
      display:flex; align-items:center; gap:12px; margin-bottom:18px;
    }
    .brand .logo{
      width:40px; height:40px; border-radius:8px;
      background: linear-gradient(135deg, #2563eb, #7c3aed);
      box-shadow:0 8px 20px rgba(37,99,235,0.4);
    }
    .brand .title{
      font-weight:700; letter-spacing:0.2px; font-size:18px; color:#ffffff;
    }

    h1{ margin:0 0 8px; font-size:28px; font-weight:700; }
    .subtitle{ margin:0 0 18px; color:var(--muted); font-size:14px; }

    .field{
      margin-bottom:14px;
    }
    label{
      display:block; margin:0 0 8px; font-size:13px; color:var(--muted);
    }
    input[type="text"], input[type="email"], input[type="password"]{
      width:100%; padding:12px 14px; border-radius:10px;
      border:1px solid var(--border); background:#0b1220; color:var(--text);
      outline:none; transition: border-color .18s ease, box-shadow .18s ease;
    }
    input:focus{
      border-color: #3b82f6;
      box-shadow: 0 0 0 3px rgba(59,130,246,0.15);
    }

    .actions{
      display:flex; align-items:center; justify-content:space-between; margin-top:8px;
    }
    .actions a{ color:#93c5fd; text-decoration:none; font-size:13px; }
    .actions a:hover{ text-decoration:underline; }

    .btn{
      display:inline-flex; align-items:center; justify-content:center;
      gap:8px; padding:12px 14px; border-radius:10px; border:1px solid transparent;
      background:var(--primary); color:#fff; font-weight:600; cursor:pointer;
      transition: background .18s ease, transform .06s ease;
    }
    .btn:hover{ background:var(--primary-700); }
    .btn:active{ transform: translateY(1px); }

    .divider{
      display:flex; align-items:center; gap:10px; margin:18px 0;
      color:var(--muted); font-size:13px;
    }
    .divider::before, .divider::after{
      content:""; flex:1; height:1px; background:var(--border);
    }

    .providers{
      display:grid; grid-template-columns: repeat(2, 1fr); gap:10px;
    }
    @media (max-width:560px){ .providers{ grid-template-columns: 1fr; } }

    .btn-secondary{
      background:#0b1220; border-color:var(--border); color:var(--text);
    }
    .btn-secondary:hover{ border-color:#334155; background:#0e1626; }

    .foot{
      margin-top:16px; font-size:13px; color:var(--muted);
    }
    .foot a{ color:#93c5fd; text-decoration:none; }
    .foot a:hover{ text-decoration:underline; }

    /* Right visual panel */
    .visual{
      position:relative; background: radial-gradient(1200px 600px at 50% 20%, rgba(37,99,235,0.18), transparent),
                         linear-gradient(180deg, rgba(17,24,39,0.7), rgba(17,24,39,0.6));
      padding:24px;
    }
    .visual .headline{
      position:absolute; bottom:24px; left:24px; right:24px;
      color:#dbeafe;
      font-weight:600;
      text-shadow:0 2px 12px rgba(0,0,0,0.7);
    }
    .tag{
      display:inline-block; margin-top:10px; font-size:12px; color:#a5b4fc;
    }

    /* Simple alert styles if you want to surface liquid messages */
    .alert{
      margin:10px 0 14px; padding:10px 12px; border-radius:10px; font-size:13px;
      border:1px solid #334155; background:#0b1628;
    }
    .alert-error{ border-color:#7f1d1d; background:rgba(239,68,68,0.08); color:#fecaca; }
    .alert-success{ border-color:#14532d; background:rgba(22,163,74,0.08); color:#bbf7d0; }
  </style>
</head>
<body>
  <div class="container">
    <div class="card">
      <!-- Left: Sign-in form -->
      <section class="content">
        <div class="brand">
          <div class="logo" aria-hidden="true"></div>
          <div class="title">{{ website.name | default: "Contoso" }}</div>
        </div>

        <h1>Sign in</h1>
        <p class="subtitle">Access your account to manage records, view dashboards, and more.</p>

        {# Optional: Show portal messages (e.g., errors) #}
        {% assign msg = request.params['message'] %}
        {% if msg %}
          <div class="alert alert-error">{{ msg }}</div>
        {% endif %}

        <!-- Local sign-in posts to the built-in /signin endpoint -->
        <form method="post" action="/signin" autocomplete="on" novalid"{{ request.url }}"/>

          <div class="field">
            <label for="username">Email or Username</label>
            <input id="username" name="username" type="text" required placeholder="you@example.com">
          </div>

          <div class="field">
            <label for="password">Password</label>
            <input id="password" name="password" type="password" required placeholder="••••••••">
          </div>

          <div class="actions">
            /forgotpassword/Forgot password?</a>
            <button type="submit" class="btn">Sign in</button>
          </div>
        </form>

        <div class="divider"><span>Or continue with</span></div>

        <!-- External identity providers -->
        <div class="providers">
          <!-- Remove any providers you don't use -->
          <a class="btn btnAzureAD&returnUrl={{ request.url }}
            <!-- Simple icon dots -->
            <span style="width:8px;height:8px;border-radius:50%;background:#2563eb;display:inline-block"></span>
            <span>Azure AD</span>
          </a>

          <a class="btn btn-secondary" href="/signin?provider=MicrosoftAccount&returnUrl={{ request.url8px;height:8px;border-radius:50%;background:#0078d4;display:inline-block}}"></span>
            <span>Microsoft</span>
          </a>

          /signin?provider=Google&returnUrl={{ request.url }}
            <span style="width:8px;height:8px;border-radius:50%;background:#ea4335;display:inline-block"></span>
            <span>Google</span>
          </a>

          /signin?provider=LinkedIn&returnUrl={{ request.url }}
            <span style="width:8px;height:8px;border-radius:50%;background:#0a66c2;display:inline-block"></span>
            <span>LinkedIn</span>
          </a>

          /signin?provider=Facebook&returnUrl={{ request.url }}
            <span style="width:8px;height:8px;border-radius:50%;background:#1877f2;display:inline-block"></span>
            <span>Facebook</span>
          </a>
        </div>

        <div class="foot">
          <p>New here? /register/Create an account</a></p>
          <p>By signing in, you agree to our <aerms/Terms of Use</a> and <a href="/privacyPolicy</a>.</p>
        </div>
      </section>

      <!-- Right: Visual / marketing panel -->
      <aside class="visual">
        <!-- You can replace this with an image: <img src="/-/media/your -->
        <h3 class="headline">
          Secure access to your Power Pages site.<br>
          Role-based permissions. Seamless external identity. Auditable sign-ins.
          <div class="tag">Powered by Microsoft Dataverse & Power Pages</div>
        </h3>
      </aside>
    </div>
  </div>

  <!-- Optional: light client-side validation -->
  <script>
    (function(){
      const form = document.querySelector('form[action="/signin"]');
      if(!form) return;
      form.addEventListener('submit', function(e){
        const u = form.querySelector('[name="username"]');
        const p = form.querySelector('[name="password"]');
        if(!u.value.trim() || !p.value.trim()){
          e.preventDefault();
          alert('Please enter your username and password.');
        }
      });
    })();
  </script>
</body>
</html>
",
  "publishingstateid": "706c8d44-f8a7-4d37-803a-01690654b0df",
  "enablerating": false,
  "enabletracking": false,
